import React, { useState, useEffect } from 'react';
import { UserRole } from './types';
import Navbar from './components/Navbar';
import FarmerView from './views/FarmerView';
import BeekeeperView from './views/BeekeeperView';
import AdminView from './views/AdminView';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.FARMER);
  const [activeTab, setActiveTab] = useState('inicio');

  // Reset tab when role changes
  useEffect(() => {
    setActiveTab('inicio');
  }, [role]);

  const renderContent = () => {
    switch (role) {
      case UserRole.FARMER:
        return <FarmerView activeTab={activeTab} setActiveTab={setActiveTab} />;
      case UserRole.BEEKEEPER:
        return <BeekeeperView activeTab={activeTab} setActiveTab={setActiveTab} />;
      case UserRole.ADMIN:
        return <AdminView activeTab={activeTab} setActiveTab={setActiveTab} />;
      default:
        return <div>Error de Rol</div>;
    }
  };

  return (
    <div className="flex flex-col min-h-screen">
      <Navbar 
        role={role} 
        setRole={setRole} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
      />
      <main className="flex-grow pt-20 pb-12">
        {renderContent()}
      </main>
      <footer className="bg-[#1A1A1A] text-white py-8 border-t-4 border-[#FFBF00]">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-sm opacity-60">© 2024 BeePoliniza Pro-AI. Innovando por la biodiversidad y la agricultura sostenible.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { UserRole } from '../types';
import { LayoutDashboard, ShoppingBag, Map, FileText, BarChart3, HelpCircle, Settings, ShieldCheck } from 'lucide-react';

interface NavbarProps {
  role: UserRole;
  setRole: (role: UserRole) => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ role, setRole, activeTab, setActiveTab }) => {
  const navItems = {
    [UserRole.FARMER]: [
      { id: 'inicio', label: 'Inicio', icon: LayoutDashboard },
      { id: 'market', label: 'Marketplace', icon: ShoppingBag },
      { id: 'beetrack', label: 'BeeTrack IoT', icon: Map },
      { id: 'contracts', label: 'Contratos', icon: FileText },
      { id: 'metrics', label: 'Métricas', icon: BarChart3 },
      { id: 'help', label: 'Ayuda', icon: HelpCircle },
    ],
    [UserRole.BEEKEEPER]: [
      { id: 'inicio', label: 'Dashboard', icon: LayoutDashboard },
      { id: 'market', label: 'Demandas', icon: ShoppingBag },
      { id: 'beetrack', label: 'Apiarios', icon: Map },
      { id: 'contracts', label: 'Gestión', icon: FileText },
      { id: 'metrics', label: 'Rendimiento', icon: BarChart3 },
    ],
    [UserRole.ADMIN]: [
      { id: 'inicio', label: 'Control Global', icon: ShieldCheck },
      { id: 'moderation', label: 'Moderación', icon: Settings },
      { id: 'users', label: 'Usuarios', icon: FileText },
      { id: 'impact', label: 'Reporte Ambiental', icon: BarChart3 },
    ]
  };

  return (
    <nav className="fixed top-0 w-full bg-white/90 backdrop-blur-md shadow-sm z-50 border-b border-gray-200">
      <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
        {/* Logo */}
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setActiveTab('inicio')}>
          <div className="w-10 h-10 bg-[#FFBF00] rounded-xl flex items-center justify-center text-[#1A1A1A] shadow-lg shadow-yellow-200">
            <svg viewBox="0 0 24 24" className="w-6 h-6 fill-current" xmlns="http://www.w3.org/2000/svg">
                <path d="M12 2L4.5 6.33V15L12 19.33L19.5 15V6.33L12 2ZM17.5 13.84L12 17.03L6.5 13.84V7.83L12 4.64L17.5 7.83V13.84Z"/>
                <path d="M12 8L10 9.15V11.46L12 12.61L14 11.46V9.15L12 8Z"/>
            </svg>
          </div>
          <div>
            <h1 className="font-bold text-xl text-[#1A1A1A] leading-none">BeePoliniza</h1>
            <span className="text-[10px] font-bold tracking-widest text-[#FFBF00] uppercase">Pro-AI Ecosystem</span>
          </div>
        </div>

        {/* Dynamic Navigation */}
        <div className="hidden md:flex items-center gap-1">
          {navItems[role].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`px-4 py-2 rounded-lg flex items-center gap-2 transition-all duration-200 ${
                activeTab === item.id 
                  ? 'bg-[#FFBF00] text-[#1A1A1A] font-semibold' 
                  : 'text-gray-600 hover:bg-gray-100'
              }`}
            >
              <item.icon size={18} />
              <span className="text-sm">{item.label}</span>
            </button>
          ))}
        </div>

        {/* Role Selector (Demo Simulation) */}
        <div className="flex items-center gap-3">
          <select 
            value={role}
            onChange={(e) => setRole(e.target.value as UserRole)}
            className="bg-gray-100 border-none rounded-full px-4 py-2 text-xs font-bold text-[#1A1A1A] outline-none hover:bg-gray-200 transition-colors"
          >
            <option value={UserRole.FARMER}>Rol: Agricultor</option>
            <option value={UserRole.BEEKEEPER}>Rol: Apicultor</option>
            <option value={UserRole.ADMIN}>Rol: Admin</option>
          </select>
          <div className="w-10 h-10 rounded-full bg-gray-200 border-2 border-white shadow-sm overflow-hidden">
            <img src={`https://picsum.photos/seed/${role}/100/100`} alt="Avatar" />
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
